# Category: hardcoded_secrets

import os
import sys
import boto3
from botocore.exceptions import ClientError, NoCredentialsError


def get_credentials():
    """
    Retrieve AWS credentials from environment variables.
    
    Before running this script, set the following environment variables:
    
    On Linux/macOS:
        export AWS_ACCESS_KEY_ID="your-access-key-id"
        export AWS_SECRET_ACCESS_KEY="your-secret-access-key"
        export AWS_S3_BUCKET_NAME="your-bucket-name"
        export AWS_DEFAULT_REGION="us-east-1"  # optional
    
    On Windows (PowerShell):
        $env:AWS_ACCESS_KEY_ID="your-access-key-id"
        $env:AWS_SECRET_ACCESS_KEY="your-secret-access-key"
        $env:AWS_S3_BUCKET_NAME="your-bucket-name"
        $env:AWS_DEFAULT_REGION="us-east-1"  # optional
    
    Alternatively, you can use AWS Secrets Manager, SSM Parameter Store,
    or a .env file loaded via python-dotenv (never commit .env to version control).
    """
    access_key = os.environ.get("AWS_ACCESS_KEY_ID")
    secret_key = os.environ.get("AWS_SECRET_ACCESS_KEY")
    bucket_name = os.environ.get("AWS_S3_BUCKET_NAME", "demo-bucket")
    region = os.environ.get("AWS_DEFAULT_REGION", "us-east-1")

    if not access_key or not secret_key:
        print("ERROR: AWS credentials not found in environment variables.")
        print()
        print("Please set them before running this script:")
        print()
        print('  export AWS_ACCESS_KEY_ID="your-access-key-id"')
        print('  export AWS_SECRET_ACCESS_KEY="your-secret-access-key"')
        print('  export AWS_S3_BUCKET_NAME="your-bucket-name"')
        print()
        print("IMPORTANT: Never hardcode credentials in source code.")
        print("           Never commit credentials to version control.")
        sys.exit(1)

    return access_key, secret_key, bucket_name, region


def list_s3_files(access_key, secret_key, bucket_name, region):
    """Connect to S3 and list all files in the specified bucket."""
    try:
        s3_client = boto3.client(
            "s3",
            aws_access_key_id=access_key,
            aws_secret_access_key=secret_key,
            region_name=region,
        )

        print(f"Connecting to S3 bucket: {bucket_name}")
        print(f"Region: {region}")
        print("-" * 60)

        paginator = s3_client.get_paginator("list_objects_v2")
        page_iterator = paginator.paginate(Bucket=bucket_name)

        file_count = 0
        total_size = 0

        for page in page_iterator:
            if "Contents" not in page:
                continue
            for obj in page["Contents"]:
                file_count += 1
                total_size += obj["Size"]
                size_kb = obj["Size"] / 1024
                last_modified = obj["LastModified"].strftime("%Y-%m-%d %H:%M:%S")
                print(f"  {obj['Key']:<50} {size_kb:>10.1f} KB    {last_modified}")

        print("-" * 60)
        if file_count == 0:
            print("Bucket is empty — no files found.")
        else:
            print(f"Total files: {file_count}")
            print(f"Total size:  {total_size / (1024 * 1024):.2f} MB")

    except NoCredentialsError:
        print("ERROR: Invalid or missing AWS credentials.")
        sys.exit(1)
    except ClientError as e:
        error_code = e.response["Error"]["Code"]
        error_msg = e.response["Error"]["Message"]
        print(f"ERROR: AWS returned {error_code} — {error_msg}")
        sys.exit(1)
    except Exception as e:
        print(f"ERROR: Unexpected error — {e}")
        sys.exit(1)


def main():
    access_key, secret_key, bucket_name, region = get_credentials()
    list_s3_files(access_key, secret_key, bucket_name, region)


if __name__ == "__main__":
    main()